import Header from '../components/header/Header'
import Home from '../pages/home/Home'
import Section from '../pages/section/Section'


export const routes = [ 
    {
        path: '/',
        element: <Home />
    },
    {
        path: '/home',
        element: <Home />
    },
    {
        path: '/section',
        element: <Section />
    },
    {
        path: '/header',
        element: <Header />
    },
    {
        path: '/notFound',
        element: <NotFound />
    }
]
